using UnityEngine;

public class SFXManager : MonoBehaviour
{
    public static SFXManager Instance;

    // Audio clips
    public AudioClip coinSound;
    public AudioClip jumpSound;
    public AudioClip attackSound;
    public AudioClip hitSound;
    public AudioClip deathSound;
    public AudioClip winSound;
    public AudioClip buttonClickSound;
    public AudioClip menuOpenSound;
    public AudioClip levelCompleteSound;

    private AudioSource audioSource;

    void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }

        audioSource = GetComponent<AudioSource>();
        if (audioSource == null)
        {
            audioSource = gameObject.AddComponent<AudioSource>();
        }
    }

    // --- Event-based sound effects ---

    public void PlayCoinSound()
    {
        PlaySFX(coinSound);
    }

    public void PlayJumpSound()
    {
        PlaySFX(jumpSound);
    }

    public void PlayAttackSound()
    {
        PlaySFX(attackSound);
    }

    public void PlayHitSound()
    {
        PlaySFX(hitSound);
    }

    public void PlayDeathSound()
    {
        PlaySFX(deathSound);
    }

    public void PlayWinSound()
    {
        PlaySFX(winSound);
    }

    public void PlayButtonClickSound()
    {
        PlaySFX(buttonClickSound);
    }

    public void PlayMenuOpenSound()
    {
        PlaySFX(menuOpenSound);
    }

    public void PlayLevelCompleteSound()
    {
        PlaySFX(levelCompleteSound);
    }

    // Generic SFX player with volume and pitch control
    public void PlaySFX(AudioClip clip, float volume = 1f, float pitch = 1f)
    {
        if (clip != null)
        {
            audioSource.pitch = pitch;
            audioSource.PlayOneShot(clip, volume);
            audioSource.pitch = 1f;
        }
    }

    // Play random from a list
    public void PlayRandomSFX(AudioClip[] clips, float volume = 1f)
    {
        if (clips != null && clips.Length > 0)
        {
            int index = Random.Range(0, clips.Length);
            PlaySFX(clips[index], volume);
        }
    }

    // Play with random pitch
    public void PlaySFXRandomPitch(AudioClip clip, float minPitch = 0.9f, float maxPitch = 1.1f, float volume = 1f)
    {
        if (clip != null)
        {
            float pitch = Random.Range(minPitch, maxPitch);
            PlaySFX(clip, volume, pitch);
        }
    }
}

// Example usage in other scripts
public class SFXUsage : MonoBehaviour
{
    public void OnCoinCollected()
    {
        if (SFXManager.Instance != null)
        {
            SFXManager.Instance.PlayCoinSound();
        }
    }

    public void OnPlayerJump()
    {
        if (SFXManager.Instance != null)
        {
            SFXManager.Instance.PlayJumpSound();
        }
    }

    public void OnPlayerHit()
    {
        if (SFXManager.Instance != null)
        {
            SFXManager.Instance.PlayHitSound();
        }
    }

    public void OnButtonClick()
    {
        if (SFXManager.Instance != null)
        {
            SFXManager.Instance.PlayButtonClickSound();
        }
    }
}

